     1→#!/usr/bin/env node
     2→/**
     3→ * Claude Code stdin hook handler.
     4→ *
     5→ * Reads a hook event from stdin, maintains a markdown sessions table, and
     6→ * writes a JSON response to stdout.
     7→ *
     8→ * Configure in ~/.claude/settings.json:
     9→ *
    10→ *   {
    11→ *     "hooks": {
    12→ *       "PreToolUse": [{
    13→ *         "matcher": ".*",
    14→ *         "hooks": [{ "type": "command", "command": "claude-hook-handler --sessions ~/.claude/sessions.md" }]
    15→ *       }],
    16→ *       ...
    17→ *     }
    18→ *   }
    19→ */
    20→import Anthropic from "@anthropic-ai/sdk";
    21→import {
    22→  readFileSync,
    23→  writeFileSync,
    24→  appendFileSync,
    25→  existsSync,
    26→  mkdirSync,
    27→  renameSync,
    28→  readdirSync,
    29→  unlinkSync,
    30→} from "fs";
    31→import { dirname, join, resolve, basename } from "path";
    32→import { homedir } from "os";
    33→import { execSync, spawnSync } from "child_process";
    34→import { Command } from "commander";
    35→import type {
    36→  HookInput,
    37→  SyncHookJSONOutput,
    38→  PreToolUseHookInput,
    39→  PostToolUseHookInput,
    40→  PostToolUseFailureHookInput,
    41→  SubagentStartHookInput,
    42→} from "@anthropic-ai/claude-agent-sdk";
    43→
    44→// ─── Path helpers ─────────────────────────────────────────────────────────────
    45→
    46→function expandHome(p: string): string {
    47→  return p.startsWith("~/") ? join(homedir(), p.slice(2)) : resolve(p);
    48→}
    49→
    50→// ─── Config file ──────────────────────────────────────────────────────────────
    51→
    52→const CONFIG_PATH = join(homedir(), ".claude", "hook-handler.json");
    53→
    54→interface Config {
    55→  anthropicApiKey?: string;
    56→  /**
    57→   * Path to a git repository where session logs are committed.
    58→   * When set, sessions.md and the sessions/ folder are stored inside this
    59→   * directory instead of the default ~/.claude location.
    60→   * The --sessions CLI flag still overrides this value.
    61→   *
    62→   * Example: { "repository": "~/notes/claude-sessions" }
    63→   */
    64→  repository?: string;
    65→}
    66→
    67→function loadConfig(): Config {
    68→  try {
    69→    const raw = readFileSync(CONFIG_PATH, "utf8");
    70→    const config = JSON.parse(raw) as Config;
    71→    if (config.anthropicApiKey && !process.env.ANTHROPIC_API_KEY) {
    72→      process.env.ANTHROPIC_API_KEY = config.anthropicApiKey;
    73→    }
    74→    return config;
    75→  } catch {
    76→    // Config file is optional — no-op if missing or unreadable
    77→    return {};
    78→  }
    79→}
    80→
    81→// ─── Git user ─────────────────────────────────────────────────────────────────
    82→
    83→interface GitUser {
    84→  name?: string;
    85→  email?: string;
    86→}
    87→
    88→function gitUser(): GitUser {
    89→  const get = (key: string): string | undefined => {
    90→    try {
    91→      return execSync(`git config --global ${key}`, {
    92→        encoding: "utf8",
    93→        stdio: ["ignore", "pipe", "ignore"],
    94→      }).trim() || undefined;
    95→    } catch { return undefined; }
    96→  };
    97→  return { name: get("user.name"), email: get("user.email") };
    98→}
    99→
   100→// ─── Git repo detection ───────────────────────────────────────────────────────
   101→
   102→interface RepoInfo {
   103→  repoRoot: string;
   104→  repoName: string;
   105→}
   106→
   107→function detectRepo(cwd: string): RepoInfo | undefined {
   108→  try {
   109→    const root = execSync("git rev-parse --show-toplevel", {
   110→      cwd,
   111→      encoding: "utf8",
   112→      stdio: ["ignore", "pipe", "ignore"],
   113→    }).trim();
   114→    return { repoRoot: root, repoName: basename(root) };
   115→  } catch {
   116→    return undefined;
   117→  }
   118→}
   119→
   120→// ─── Session state ────────────────────────────────────────────────────────────
   121→
   122→interface SessionRecord {
   123→  sessionId: string;
   124→  startedAt: string;
   125→  updatedAt: string;
   126→  cwd: string;
   127→  repoRoot?: string;
   128→  repoName?: string;
   129→  parentSessionId?: string;
   130→  gitUserName?: string;
   131→  gitUserEmail?: string;
   132→  prompt?: string;
   133→  summary?: string;
   134→  keywords?: string[];
   135→}
   136→
   137→interface PendingToolUse {
   138→  tool_use_id: string;
   139→  tool_name: string;
   140→  tool_input?: unknown;
   141→  startedAt: string; // pre-formatted timestamp
   142→}
   143→
   144→// ─── Event record (NDJSON primary store) ──────────────────────────────────────
   145→
   146→interface EventRecord {
   147→  timestamp: string;
   148→  event: string;
   149→  blocked: boolean;
   150→  data: HookInput;
   151→  // Derived fields stored for reconstruction without re-running AI
   152→  summary?: string;
   153→  keywords?: string[];
   154→}
   155→
   156→interface State {
   157→  sessions: Record<string, SessionRecord>;
   158→  // Maps agent_id → parent session_id so we can link child SessionStart events
   159→  agentParents: Record<string, string>;
   160→  // Maps tool_use_id → stashed PreToolUse data, cleared on PostToolUse
   161→  pendingToolUses: Record<string, PendingToolUse>;
   162→}
   163→
   164→function readState(statePath: string): State {
   165→  try {
   166→    const s = JSON.parse(readFileSync(statePath, "utf8")) as Partial<State>;
   167→    return {
   168→      sessions: s.sessions ?? {},
   169→      agentParents: s.agentParents ?? {},
   170→      pendingToolUses: s.pendingToolUses ?? {},
   171→    };
   172→  } catch {
   173→    return { sessions: {}, agentParents: {}, pendingToolUses: {} };
   174→  }
   175→}
   176→
   177→function writeState(statePath: string, state: State): void {
   178→  mkdirSync(dirname(statePath), { recursive: true });
   179→  const tmp = statePath + ".tmp";
   180→  writeFileSync(tmp, JSON.stringify(state, null, 2), "utf8");
   181→  renameSync(tmp, statePath); // atomic on same filesystem
   182→}
   183→
   184→// ─── Markdown rendering ───────────────────────────────────────────────────────
   185→
   186→function fmt(iso: string): string {
   187→  const d = new Date(iso);
   188→  const dd  = String(d.getDate()).padStart(2, "0");
   189→  const mm  = String(d.getMonth() + 1).padStart(2, "0");
   190→  const yy  = String(d.getFullYear()).slice(2);
   191→  const hh  = String(d.getHours()).padStart(2, "0");
   192→  const min = String(d.getMinutes()).padStart(2, "0");
   193→  return `${dd}/${mm}/${yy} ${hh}:${min}`;
   194→}
   195→
   196→function escapeCell(s: string): string {
   197→  return s.replace(/\|/g, "\\|").replace(/\n/g, " ");
   198→}
   199→
   200→function renderMarkdown(state: State): string {
   201→  const sessions = Object.values(state.sessions).sort((a, b) =>
   202→    b.updatedAt.localeCompare(a.updatedAt),
   203→  );
   204→
   205→  const updatedAt = `${fmt(new Date().toISOString())} UTC`;
   206→
   207→  if (sessions.length === 0) {
   208→    return (
   209→      `# Claude Code Sessions\n\n` +
   210→      `*No active sessions.*\n\n` +
   211→      `*Last updated: ${updatedAt}*\n`
   212→    );
   213→  }
   214→
   215→  const header = "| Session ID | User | Repo | Summary | Keywords | Started | Last Updated |";
   216→  const divider = "|---|---|---|---|---|---|---|";
   217→  const rows = sessions.map((s) => {
   218→    const id = `[\`${s.sessionId.slice(0, 8)}…\`](sessions/${s.sessionId}.md)`;
   219→    const user = escapeCell(
   220→      s.gitUserName && s.gitUserEmail ? `${s.gitUserName} <${s.gitUserEmail}>`
   221→      : s.gitUserName ?? s.gitUserEmail ?? "",
   222→    );
   223→    const repo = escapeCell(s.repoName ?? s.cwd.split("/").pop() ?? s.cwd);
   224→    const summary = escapeCell(
   225→      s.summary ?? s.prompt?.slice(0, 80) ?? "*waiting for prompt…*",
   226→    );
   227→    const keywords = s.keywords?.length
   228→      ? s.keywords.map((k) => `\`${escapeCell(k)}\``).join(" ")
   229→      : "";
   230→    return `| ${id} | ${user} | ${repo} | ${summary} | ${keywords} | ${fmt(s.startedAt)} | ${fmt(s.updatedAt)} |`;
   231→  });
   232→
   233→  return [
   234→    "# Claude Code Sessions",
   235→    "",
   236→    header,
   237→    divider,
   238→    ...rows,
   239→    "",
   240→    `*Last updated: ${updatedAt}*`,
   241→    "",
   242→  ].join("\n");
   243→}
   244→
   245→function writeMarkdown(sessionsPath: string, state: State): void {
   246→  mkdirSync(dirname(sessionsPath), { recursive: true });
   247→  const tmp = sessionsPath + ".tmp";
   248→  writeFileSync(tmp, renderMarkdown(state), "utf8");
   249→  renameSync(tmp, sessionsPath);
   250→}
   251→
   252→// ─── Per-session event log ────────────────────────────────────────────────────
   253→
   254→// Always omit — structural noise with no reader value
   255→const SKIP_COMMON = new Set([
   256→  "session_id", "hook_event_name", "transcript_path", "tool_use_id",
   257→]);
   258→// Also omit for collapsed events (same for every tool call — not useful per-event)
   259→const SKIP_NOISE = new Set([...SKIP_COMMON, "cwd", "permission_mode"]);
   260→
   261→const IMPORTANT_EVENTS = new Set([
   262→  "UserPromptSubmit", "Stop", "SessionEnd",
   263→]);
   264→
   265→const SKIP_EVENTS = new Set([
   266→  "SessionStart",
   267→]);
   268→
   269→/** Extract a short hint string from tool_input for the <summary> line. */
   270→function toolSummaryHint(toolName: string, toolInput: unknown): string {
   271→  if (!toolInput || typeof toolInput !== "object") return "";
   272→  const inp = toolInput as Record<string, unknown>;
   273→  const str = (k: string): string | undefined =>
   274→    typeof inp[k] === "string" ? String(inp[k]) : undefined;
   275→  switch (toolName) {
   276→    case "Read":      return str("file_path") ?? "";
   277→    case "Write":     return str("file_path") ?? "";
   278→    case "Edit":      return str("file_path") ?? "";
   279→    case "Bash":      return (str("command") ?? "").slice(0, 70);
   280→    case "Glob":      return str("pattern") ?? "";
   281→    case "Grep":      return str("pattern") ?? "";
   282→    case "WebFetch":  return str("url") ?? "";
   283→    case "WebSearch": return str("query") ?? "";
   284→    default:          return "";
   285→  }
   286→}
   287→
   288→/** Render fields for an event, skipping the given skip-set. */
   289→function renderFields(
   290→  input: HookInput,
   291→  skip: Set<string>,
   292→  childLogRelPath?: string,
   293→): string[] {
   294→  const lines: string[] = [];
   295→  for (const [key, value] of Object.entries(input)) {
   296→    if (skip.has(key) || value === undefined) continue;
   297→    if (key === "prompt" || key === "message" || key === "last_assistant_message") {
   298→      lines.push(`**${key}:**`, "");
   299→      for (const line of String(value).split("\n")) lines.push(`> ${line}`);
   300→      lines.push("");
   301→    } else if (key === "tool_input" || key === "tool_response") {
   302→      const s = JSON.stringify(value, null, 2);
   303→      lines.push(`**${key}:**`, "```json", s.length > 600 ? s.slice(0, 600) + "\n…" : s, "```", "");
   304→    } else if (key === "agent_id" && childLogRelPath) {
   305→      lines.push(`- **${key}:** [\`${String(value)}\`](${childLogRelPath})`);
   306→    } else {
   307→      lines.push(`- **${key}:** \`${String(value)}\``);
   308→    }
   309→  }
   310→  return lines;
   311→}
   312→
   313→/** Important events: H2 heading, full field list, horizontal rule. */
   314→function formatImportantEvent(input: HookInput): string {
   315→  const ts = fmt(new Date().toISOString());
   316→  const name = input.hook_event_name;
   317→  const sym = EVENT_SYMBOL[name] ?? "◆";
   318→  const fields = renderFields(input, SKIP_COMMON);
   319→  return [`## ${sym} ${name}`, "", `<small>${ts}</small>`, "", ...fields, "---", ""].join("\n");
   320→}
   321→
   322→/** UserPromptSubmit: "<User> prompted:" followed by the prompt as a blockquote. */
   323→function formatPromptEvent(input: HookInput, rec: SessionRecord | undefined): string {
   324→  const ts = fmt(new Date().toISOString());
   325→  const user = rec?.gitUserName ?? rec?.gitUserEmail ?? "User";
   326→  const prompt = "prompt" in input ? String(input.prompt) : "";
   327→  const lines: string[] = [`## → **${user} prompted:**`, "", `<small>${ts}</small>`, ""];
   328→  for (const line of prompt.split("\n")) lines.push(`> ${line}`);
   329→  lines.push("", "---", "");
   330→  return lines.join("\n");
   331→}
   332→
   333→/** Stop / Notification: "Claude wrote:" followed by the message as a blockquote. */
   334→function formatClaudeMessageEvent(input: HookInput): string {
   335→  const ts = fmt(new Date().toISOString());
   336→  const sym = EVENT_SYMBOL[input.hook_event_name] ?? "◆";
   337→  const message =
   338→    "last_assistant_message" in input && input.last_assistant_message
   339→      ? String(input.last_assistant_message)
   340→      : "message" in input && input.message
   341→      ? String(input.message)
   342→      : "";
   343→
   344→  if (!message) return formatImportantEvent(input);
   345→
   346→  const lines: string[] = [`## ${sym} **Claude wrote:**`, "", `<small>${ts}</small>`, ""];
   347→  for (const line of message.split("\n")) lines.push(`> ${line}`);
   348→  lines.push("", "---", "");
   349→  return lines.join("\n");
   350→}
   351→
   352→/** Non-critical events: collapsed <details> block. */
   353→function formatCollapsibleEvent(input: HookInput, childLogRelPath?: string): string {
   354→  const ts = fmt(new Date().toISOString());
   355→  const name = input.hook_event_name;
   356→  const sym = EVENT_SYMBOL[name] ?? "◆";
   357→  const fields = renderFields(input, SKIP_NOISE, childLogRelPath);
   358→  return [
   359→    `<details>`,
   360→    `<summary>${sym} ${name}</summary>`,
   361→    "",
   362→    `<small>${ts}</small>`,
   363→    "",
   364→    ...fields,
   365→    `</details>`,
   366→    "",
   367→  ].join("\n");
   368→}
   369→
   370→/** Merged Pre+PostToolUse: collapsed <details> with success/failure indicator. */
   371→function formatMergedToolUse(
   372→  pending: PendingToolUse,
   373→  post: PostToolUseHookInput | PostToolUseFailureHookInput,
   374→): string {
   375→  const failed = post.hook_event_name === "PostToolUseFailure";
   376→  const statusSym = failed ? "✗" : "✓";
   377→  const hint = toolSummaryHint(pending.tool_name, pending.tool_input);
   378→  const hintStr = hint ? ` · \`${hint.replace(/`/g, "'")}\`` : "";
   379→  const endTs = fmt(new Date().toISOString());
   380→
   381→  const lines: string[] = [
   382→    `<details>`,
   383→    `<summary>▶${statusSym} ${pending.tool_name}${hintStr}</summary>`,
   384→    "",
   385→    `<small>${pending.startedAt} → ${endTs}</small>`,
   386→    "",
   387→  ];
   388→
   389→  if (pending.tool_input !== undefined) {
   390→    const s = JSON.stringify(pending.tool_input, null, 2);
   391→    lines.push("**input:**", "```json", s.length > 600 ? s.slice(0, 600) + "\n…" : s, "```", "");
   392→  }
   393→
   394→  if (failed && "error" in post && post.error) {
   395→    lines.push(`**error:** \`${String(post.error)}\``, "");
   396→  } else if ("tool_response" in post && post.tool_response !== undefined) {
   397→    const s =
   398→      typeof post.tool_response === "string"
   399→        ? post.tool_response
   400→        : JSON.stringify(post.tool_response, null, 2);
   401→    lines.push("**output:**", "```", s.length > 400 ? s.slice(0, 400) + "\n…" : s, "```", "");
   402→  }
   403→
   404→  lines.push(`</details>`, "");
   405→  return lines.join("\n");
   406→}
   407→
   408→function sessionLogPath(sessionsPath: string, sessionId: string): string {
   409→  return join(dirname(sessionsPath), "sessions", `${sessionId}.md`);
   410→}
   411→
   412→// ─── Log rotation ─────────────────────────────────────────────────────────────
   413→
   414→function archiveTimestamp(): string {
   415→  const d = new Date();
   416→  return (
   417→    String(d.getFullYear()) +
   418→    String(d.getMonth() + 1).padStart(2, "0") +
   419→    String(d.getDate()).padStart(2, "0") +
   420→    "-" +
   421→    String(d.getHours()).padStart(2, "0") +
   422→    String(d.getMinutes()).padStart(2, "0")
   423→  );
   424→}
   425→
   426→/**
   427→ * If `logPath` exceeds `maxLines` lines, rename it to a timestamped archive,
   428→ * then write a fresh file containing only the header (with an "← prev" link).
   429→ * Returns the archive path if rotation happened, undefined otherwise.
   430→ */
   431→function rotateSessionLog(logPath: string, maxLines: number): string | undefined {
   432→  if (!existsSync(logPath)) return undefined;
   433→
   434→  const content = readFileSync(logPath, "utf8");
   435→  if (content.split("\n").length <= maxLines) return undefined;
   436→
   437→  // Build archive filename next to the current file
   438→  const dir = dirname(logPath);
   439→  const base = basename(logPath, ".md");
   440→  const archiveName = `${base}-${archiveTimestamp()}.md`;
   441→  const archivePath = join(dir, archiveName);
   442→
   443→  // Rename current file → archive
   444→  renameSync(logPath, archivePath);
   445→
   446→  // Append a forward link to the bottom of the archived file
   447→  const nextName = basename(logPath);
   448→  appendFileSync(archivePath, `\n---\n\n<small>[→ next](${nextName})</small>\n`, "utf8");
   449→
   450→  // Extract header: everything before the first event entry
   451→  const firstEventIdx = content.search(/^(?:## |<details>)/m);
   452→  let header = firstEventIdx !== -1 ? content.slice(0, firstEventIdx) : content;
   453→
   454→  // Inject / update the "← prev" link next to the session ID in the <sub> line
   455→  const prevLink = `[← prev](${archiveName})`;
   456→  if (header.includes("[← prev]")) {
   457→    // Update existing link to point to the new archive
   458→    header = header.replace(/\[← prev\]\([^)]*\)/, prevLink);
   459→  } else if (header.includes("<sub>")) {
   460→    // Insert after the backtick-wrapped session ID
   461→    header = header.replace(/(<sub>)(`[^`]+`)/, `$1$2 · ${prevLink}`);
   462→  } else {
   463→    // Fallback for bare initial header (pre-UserPromptSubmit)
   464→    header = header.replace(
   465→      /^(# Session `[^`]+`\n\n)/m,
   466→      `$1<small>${prevLink}</small>\n\n`,
   467→    );
   468→  }
   469→
   470→  writeFileSync(logPath, header, "utf8");
   471→  return archivePath;
   472→}
   473→
   474→function updateLogHeader(logPath: string, rec: SessionRecord): void {
   475→  const content = readFileSync(logPath, "utf8");
   476→
   477→  // Build the new header: AI summary as the H1, session ID + user in small text beneath
   478→  const title = rec.summary ?? `Session \`${rec.sessionId}\``;
   479→  const keywordsLine = rec.keywords?.length
   480→    ? `**Keywords:** ${rec.keywords.map((k) => `\`${k}\``).join(" ")}`
   481→    : "";
   482→
   483→  const userPart = rec.gitUserName && rec.gitUserEmail
   484→    ? ` · ${rec.gitUserName} &lt;${rec.gitUserEmail}&gt;`
   485→    : rec.gitUserName ? ` · ${rec.gitUserName}`
   486→    : rec.gitUserEmail ? ` · ${rec.gitUserEmail}`
   487→    : "";
   488→  const headerParts = [`# ${title}`, "", `<sub>\`${rec.sessionId}\`${userPart}</sub>`, ""];
   489→  if (keywordsLine) headerParts.push(keywordsLine, "");
   490→  const newHeader = headerParts.join("\n");
   491→
   492→  // Replace everything from the start of file up to the first event entry.
   493→  // Events start with ## , ### , or <details>.
   494→  const firstEventIdx = content.search(/^(?:#{2,3} |<details>)/m);
   495→  const body = firstEventIdx !== -1 ? content.slice(firstEventIdx) : "";
   496→  writeFileSync(logPath, newHeader + "\n" + body, "utf8");
   497→}
   498→
   499→function appendSessionLog(sessionsPath: string, input: HookInput, state: State, maxLogLines: number): string[] {
   500→  const logPath = sessionLogPath(sessionsPath, input.session_id);
   501→  mkdirSync(dirname(logPath), { recursive: true });
   502→
   503→  if (!existsSync(logPath)) {
   504→    writeFileSync(logPath, `# Session \`${input.session_id}\`\n\n`, "utf8");
   505→  }
   506→
   507→  // Patch the file header with summary + keywords once we have them
   508→  if (input.hook_event_name === "UserPromptSubmit") {
   509→    const rec = state.sessions[input.session_id];
   510→    if (rec) updateLogHeader(logPath, rec);
   511→  }
   512→
   513→  // ── Events to skip entirely ───────────────────────────────────────────────
   514→  if (SKIP_EVENTS.has(input.hook_event_name)) {
   515→    return [];
   516→  }
   517→
   518→  // ── PreToolUse: stash and write nothing yet ───────────────────────────────
   519→  if (input.hook_event_name === "PreToolUse") {
   520→    const pre = input as PreToolUseHookInput;
   521→    state.pendingToolUses[pre.tool_use_id] = {
   522→      tool_use_id: pre.tool_use_id,
   523→      tool_name: pre.tool_name,
   524→      tool_input: pre.tool_input,
   525→      startedAt: fmt(new Date().toISOString()),
   526→    };
   527→    return []; // nothing written to disk yet
   528→  }
   529→
   530→  // ── Log rotation (before any write) ──────────────────────────────────────
   531→  const rotatedPaths: string[] = [];
   532→  if (maxLogLines > 0) {
   533→    const archived = rotateSessionLog(logPath, maxLogLines);
   534→    if (archived) rotatedPaths.push(archived);
   535→  }
   536→
   537→  // ── PostToolUse / PostToolUseFailure: merge with stashed Pre ─────────────
   538→  if (
   539→    input.hook_event_name === "PostToolUse" ||
   540→    input.hook_event_name === "PostToolUseFailure"
   541→  ) {
   542→    const post = input as PostToolUseHookInput | PostToolUseFailureHookInput;
   543→    const pending = state.pendingToolUses[post.tool_use_id];
   544→    if (pending) {
   545→      delete state.pendingToolUses[post.tool_use_id];
   546→      appendFileSync(logPath, formatMergedToolUse(pending, post), "utf8");
   547→    } else {
   548→      // No matching Pre (e.g. state was cleared) — render as collapsible fallback
   549→      appendFileSync(logPath, formatCollapsibleEvent(input), "utf8");
   550→    }
   551→    return [...rotatedPaths, logPath];
   552→  }
   553→
   554→  // ── SubagentStart: create child log file ──────────────────────────────────
   555→  const changedPaths: string[] = [...rotatedPaths];
   556→  let childLogRelPath: string | undefined;
   557→
   558→  if (input.hook_event_name === "SubagentStart") {
   559→    const { agent_id, agent_type } = input as SubagentStartHookInput;
   560→    const childPath = sessionLogPath(sessionsPath, agent_id);
   561→    mkdirSync(dirname(childPath), { recursive: true });
   562→    if (!existsSync(childPath)) {
   563→      const parentLink = `[\`${input.session_id.slice(0, 8)}…\`](${input.session_id}.md)`;
   564→      writeFileSync(
   565→        childPath,
   566→        `# Subagent Session \`${agent_id}\`\n\n` +
   567→        `**Parent:** ${parentLink}  \n` +
   568→        `**Type:** \`${agent_type}\`\n\n`,
   569→        "utf8",
   570→      );
   571→      changedPaths.push(childPath);
   572→    }
   573→    childLogRelPath = `${agent_id}.md`;
   574→  }
   575→
   576→  // ── Important events: prominent H2 rendering ──────────────────────────────
   577→  if (input.hook_event_name === "UserPromptSubmit") {
   578→    appendFileSync(logPath, formatPromptEvent(input, state.sessions[input.session_id]), "utf8");
   579→  } else if (input.hook_event_name === "Stop" || input.hook_event_name === "Notification") {
   580→    appendFileSync(logPath, formatClaudeMessageEvent(input), "utf8");
   581→  } else if (IMPORTANT_EVENTS.has(input.hook_event_name)) {
   582→    appendFileSync(logPath, formatImportantEvent(input), "utf8");
   583→  } else {
   584→    // ── Everything else: collapsed ────────────────────────────────────────────
   585→    appendFileSync(logPath, formatCollapsibleEvent(input, childLogRelPath), "utf8");
   586→  }
   587→
   588→  changedPaths.push(logPath);
   589→  return changedPaths;
   590→}
   591→
   592→// ─── Git history ──────────────────────────────────────────────────────────────
   593→
   594→function ensureRepo(dir: string, sessionsFilename: string): void {
   595→  try {
   596→    execSync("git rev-parse --git-dir", { cwd: dir, stdio: "ignore" });
   597→  } catch {
   598→    execSync("git init", { cwd: dir, stdio: "ignore" });
   599→  }
   600→  // Always keep gitignore up to date — may need to add sessions/ on upgrade
   601→  const gitignore = join(dir, ".gitignore");
   602→  const desired =
   603→    `# Managed by claude-hook-handler\n` +
   604→    `*\n!.gitignore\n!${sessionsFilename}\n!sessions/\n!sessions/*.md\n`;
   605→  try {
   606→    if (readFileSync(gitignore, "utf8") !== desired) writeFileSync(gitignore, desired, "utf8");
   607→  } catch {
   608→    writeFileSync(gitignore, desired, "utf8");
   609→  }
   610→}
   611→
   612→function commitFiles(sessionsPath: string, paths: string[], message: string): void {
   613→  const dir = dirname(sessionsPath);
   614→  ensureRepo(dir, basename(sessionsPath));
   615→
   616→  for (const p of paths) spawnSync("git", ["add", p], { cwd: dir });
   617→
   618→  const diff = spawnSync("git", ["diff", "--cached", "--quiet"], { cwd: dir });
   619→  if (diff.status === 0) return;
   620→
   621→  spawnSync(
   622→    "git",
   623→    [
   624→      "-c", "user.name=claude-hook-handler",
   625→      "-c", "user.email=noreply@localhost",
   626→      "commit", "-m", message,
   627→    ],
   628→    { cwd: dir },
   629→  );
   630→}
   631→
   632→function buildCommitMessage(input: HookInput, state: State): string {
   633→  const id = input.session_id.slice(0, 8);
   634→  switch (input.hook_event_name) {
   635→    case "SessionStart": {
   636→      const rec = state.sessions[input.session_id];
   637→      const repo = rec?.repoName ? ` (${rec.repoName})` : "";
   638→      return `session started: ${id}${repo}`;
   639→    }
   640→    case "UserPromptSubmit": {
   641→      const rec = state.sessions[input.session_id];
   642→      const summary = rec?.summary ?? rec?.prompt?.slice(0, 60) ?? "";
   643→      return `session prompt: ${id}: ${summary}`;
   644→    }
   645→    case "SessionEnd":
   646→      return `session ended: ${id}`;
   647→    default: {
   648→      const count = Object.keys(state.sessions).length;
   649→      return `sessions: ${count} active`;
   650→    }
   651→  }
   652→}
   653→
   654→// ─── Prompt summarisation ─────────────────────────────────────────────────────
   655→
   656→interface PromptAnalysis {
   657→  summary: string;
   658→  keywords: string[];
   659→}
   660→
   661→async function analyse(prompt: string): Promise<PromptAnalysis> {
   662→  if (!process.env.ANTHROPIC_API_KEY) {
   663→    return truncateAnalysis(prompt);
   664→  }
   665→  try {
   666→    const client = new Anthropic();
   667→    const response = await client.messages.create({
   668→      model: "claude-haiku-4-5",
   669→      max_tokens: 120,
   670→      messages: [
   671→        {
   672→          role: "user",
   673→          content:
   674→            `Analyse the following user prompt. Reply with a JSON object only — no prose, no code fences.\n` +
   675→            `{\n` +
   676→            `  "summary": "<one sentence, 10 words max, no trailing punctuation>",\n` +
   677→            `  "keywords": ["<3-6 keywords: named entities, tools, concepts, actions>"]\n` +
   678→            `}\n\nPrompt:\n${prompt}`,
   679→        },
   680→      ],
   681→    });
   682→    const block = response.content[0];
   683→    if (block?.type === "text") {
   684→      // Strip markdown code fences in case the model wraps its JSON
   685→      const raw = block.text.trim()
   686→        .replace(/^```(?:json)?\s*/i, "")
   687→        .replace(/\s*```$/, "");
   688→      const parsed = JSON.parse(raw) as Partial<PromptAnalysis>;
   689→      return {
   690→        summary: String(parsed.summary ?? "").replace(/[.!?]$/, ""),
   691→        keywords: Array.isArray(parsed.keywords) ? parsed.keywords.map(String) : [],
   692→      };
   693→    }
   694→  } catch {
   695→    // fall through
   696→  }
   697→  return truncateAnalysis(prompt);
   698→}
   699→
   700→function truncateAnalysis(prompt: string): PromptAnalysis {
   701→  const firstLine = prompt.split("\n")[0]?.trim() ?? prompt;
   702→  return {
   703→    summary: firstLine.length > 80 ? firstLine.slice(0, 77) + "…" : firstLine,
   704→    keywords: [],
   705→  };
   706→}
   707→
   708→// ─── State mutation per event ─────────────────────────────────────────────────
   709→
   710→async function applyEvent(
   711→  state: State,
   712→  input: HookInput,
   713→  noSummary: boolean,
   714→  precomputed?: { summary: string; keywords: string[] },
   715→): Promise<void> {
   716→  const { session_id, hook_event_name, cwd } = input;
   717→  const now = new Date().toISOString();
   718→
   719→  switch (hook_event_name) {
   720→    case "SessionStart": {
   721→      const repo = detectRepo(cwd);
   722→      const parentSessionId = state.agentParents[session_id];
   723→      const user = gitUser();
   724→      state.sessions[session_id] = {
   725→        sessionId: session_id,
   726→        startedAt: now,
   727→        updatedAt: now,
   728→        cwd,
   729→        repoRoot: repo?.repoRoot,
   730→        repoName: repo?.repoName,
   731→        parentSessionId,
   732→        gitUserName: user.name,
   733→        gitUserEmail: user.email,
   734→      };
   735→      break;
   736→    }
   737→
   738→    case "SubagentStart": {
   739→      const { agent_id } = input as SubagentStartHookInput;
   740→      state.agentParents[agent_id] = session_id;
   741→      // Touch parent updatedAt
   742→      const existing = state.sessions[session_id];
   743→      if (existing) existing.updatedAt = now;
   744→      break;
   745→    }
   746→
   747→    case "UserPromptSubmit": {
   748→      const prompt = "prompt" in input ? String(input.prompt) : "";
   749→      const existing = state.sessions[session_id];
   750→      const { summary, keywords } = precomputed ?? (noSummary ? truncateAnalysis(prompt) : await analyse(prompt));
   751→      // Detect repo now if SessionStart was missed
   752→      const repo = existing?.repoRoot ? undefined : detectRepo(existing?.cwd ?? cwd);
   753→      state.sessions[session_id] = {
   754→        sessionId: session_id,
   755→        startedAt: existing?.startedAt ?? now,
   756→        updatedAt: now,
   757→        cwd: existing?.cwd ?? cwd,
   758→        repoRoot: existing?.repoRoot ?? repo?.repoRoot,
   759→        repoName: existing?.repoName ?? repo?.repoName,
   760→        parentSessionId: existing?.parentSessionId,
   761→        gitUserName: existing?.gitUserName,
   762→        gitUserEmail: existing?.gitUserEmail,
   763→        prompt,
   764→        summary,
   765→        keywords,
   766→      };
   767→      break;
   768→    }
   769→
   770→    case "SessionEnd": {
   771→      delete state.sessions[session_id];
   772→      break;
   773→    }
   774→
   775→    case "PreToolUse":
   776→      // Don't update sessions table — too frequent, makes updatedAt meaningless
   777→      break;
   778→
   779→    default: {
   780→      // Touch updatedAt for any other event
   781→      const existing = state.sessions[session_id];
   782→      if (existing) {
   783→        existing.updatedAt = now;
   784→      }
   785→      break;
   786→    }
   787→  }
   788→}
   789→
   790→// ─── stderr formatting ────────────────────────────────────────────────────────
   791→
   792→const EVENT_SYMBOL: Record<string, string> = {
   793→  PreToolUse:         "▶",
   794→  PostToolUse:        "✓",
   795→  PostToolUseFailure: "✗",
   796→  SessionStart:       "◉",
   797→  SessionEnd:         "◎",
   798→  Stop:               "■",
   799→  UserPromptSubmit:   "→",
   800→  Notification:       "◆",
   801→  Setup:              "⚙",
   802→  SubagentStart:      "▷",
   803→  SubagentStop:       "◁",
   804→  PermissionRequest:  "?",
   805→  PreCompact:         "⌃",
   806→};
   807→
   808→function formatForStderr(input: HookInput, blocked: boolean): string {
   809→  const ts = new Date().toISOString().replace("T", " ").slice(0, 23);
   810→  const name = input.hook_event_name;
   811→  const sym = EVENT_SYMBOL[name] ?? "◆";
   812→  const blockTag = blocked ? " \x1b[31m[BLOCKED]\x1b[0m" : "";
   813→
   814→  const lines = [`\x1b[1m[${ts}] ${sym} ${name}\x1b[0m${blockTag}`];
   815→
   816→  if ("tool_name" in input)
   817→    lines.push(`  tool:   \x1b[1m${input.tool_name}\x1b[0m`);
   818→  if ("tool_input" in input && input.tool_input !== undefined) {
   819→    const s = JSON.stringify(input.tool_input);
   820→    lines.push(`  input:  ${s.length > 120 ? s.slice(0, 120) + "…" : s}`);
   821→  }
   822→  if ("tool_response" in input && input.tool_response !== undefined) {
   823→    const s = JSON.stringify(input.tool_response);
   824→    lines.push(`  output: ${s.length > 120 ? s.slice(0, 120) + "…" : s}`);
   825→  }
   826→  if ("error" in input && input.error)
   827→    lines.push(`  error:  \x1b[31m${input.error}\x1b[0m`);
   828→  if ("prompt" in input && input.prompt)
   829→    lines.push(`  prompt: ${String(input.prompt).slice(0, 100)}`);
   830→  if ("message" in input && input.message)
   831→    lines.push(`  msg:    ${String(input.message)}`);
   832→  if ("reason" in input && input.reason)
   833→    lines.push(`  reason: ${String(input.reason)}`);
   834→  if ("source" in input && input.source)
   835→    lines.push(`  source: ${String(input.source)}`);
   836→
   837→  lines.push(`  session: \x1b[2m${input.session_id.slice(0, 8)}…\x1b[0m`);
   838→  return lines.join("\n");
   839→}
   840→
   841→// ─── Tool blocking ────────────────────────────────────────────────────────────
   842→
   843→function shouldBlock(input: HookInput, patterns: RegExp[]): boolean {
   844→  if (input.hook_event_name !== "PreToolUse" || patterns.length === 0)
   845→    return false;
   846→  const name = (input as PreToolUseHookInput).tool_name ?? "";
   847→  return patterns.some((re) => re.test(name));
   848→}
   849→
   850→function buildResponse(blocked: boolean, reason: string): SyncHookJSONOutput {
   851→  return blocked ? { decision: "block", reason } : {};
   852→}
   853→
   854→// ─── NDJSON event log (primary store) ────────────────────────────────────────
   855→
   856→/**
   857→ * Append one event record to the NDJSON event log.
   858→ * For UserPromptSubmit, also embeds `summary` and `keywords` from the already-
   859→ * computed session state so the log is self-contained for reconstruction.
   860→ */
   861→function writeEventLog(
   862→  eventsPath: string,
   863→  input: HookInput,
   864→  blocked: boolean,
   865→  state: State,
   866→): void {
   867→  const absPath = expandHome(eventsPath);
   868→  mkdirSync(dirname(absPath), { recursive: true });
   869→
   870→  const record: EventRecord = {
   871→    timestamp: new Date().toISOString(),
   872→    event: input.hook_event_name,
   873→    blocked,
   874→    data: input,
   875→  };
   876→
   877→  if (input.hook_event_name === "UserPromptSubmit") {
   878→    const session = state.sessions[input.session_id];
   879→    if (session?.summary !== undefined) record.summary = session.summary;
   880→    if (session?.keywords !== undefined) record.keywords = session.keywords;
   881→  }
   882→
   883→  appendFileSync(absPath, JSON.stringify(record) + "\n", "utf8");
   884→}
   885→
   886→// ─── Reconstruction ───────────────────────────────────────────────────────────
   887→
   888→/**
   889→ * Replay the NDJSON event log and rebuild all markdown files from scratch.
   890→ * Uses stored summary/keywords from each record so AI is never called.
   891→ */
   892→async function runReconstruct(
   893→  eventsPath: string,
   894→  sessionsPath: string,
   895→  statePath: string,
   896→  maxLogLines: number,
   897→): Promise<void> {
   898→  const absEvents = expandHome(eventsPath);
   899→  if (!existsSync(absEvents)) {
   900→    process.stderr.write(`claude-hook-handler: no event log found at ${absEvents}\n`);
   901→    process.exit(1);
   902→  }
   903→
   904→  // Clear existing markdown output so we start fresh
   905→  const absSessions = expandHome(sessionsPath);
   906→  const sessionsDir = join(dirname(absSessions), "sessions");
   907→  if (existsSync(sessionsDir)) {
   908→    for (const f of readdirSync(sessionsDir)) {
   909→      if (f.endsWith(".md")) unlinkSync(join(sessionsDir, f));
   910→    }
   911→  }
   912→  if (existsSync(absSessions)) unlinkSync(absSessions);
   913→
   914→  const state: State = { sessions: {}, agentParents: {}, pendingToolUses: {} };
   915→  const lines = readFileSync(absEvents, "utf8").split("\n");
   916→  let replayed = 0;
   917→  let skipped = 0;
   918→
   919→  for (const line of lines) {
   920→    if (!line.trim()) continue;
   921→
   922→    let record: EventRecord;
   923→    try {
   924→      record = JSON.parse(line) as EventRecord;
   925→    } catch {
   926→      skipped++;
   927→      continue;
   928→    }
   929→
   930→    const input = record.data as HookInput;
   931→    if (!input?.hook_event_name || input.hook_event_name === "Setup") continue;
   932→
   933→    const precomputed =
   934→      record.summary !== undefined
   935→        ? { summary: record.summary, keywords: record.keywords ?? [] }
   936→        : undefined;
   937→
   938→    await applyEvent(state, input, true, precomputed);
   939→    writeMarkdown(absSessions, state);
   940→    appendSessionLog(absSessions, input, state, maxLogLines);
   941→    replayed++;
   942→  }
   943→
   944→  writeState(expandHome(statePath), state);
   945→  process.stderr.write(
   946→    `claude-hook-handler reconstruct: replayed ${replayed} events` +
   947→      (skipped ? `, skipped ${skipped} malformed lines` : "") +
   948→      `\n  sessions → ${absSessions}\n`,
   949→  );
   950→}
   951→
   952→// ─── stdin ────────────────────────────────────────────────────────────────────
   953→
   954→async function readStdin(): Promise<string> {
   955→  if (process.stdin.isTTY) {
   956→    process.stderr.write(
   957→      "claude-hook-handler: no stdin detected.\n" +
   958→        "This program is called by Claude Code hooks, not directly.\n" +
   959→        "Run with --help for configuration instructions.\n",
   960→    );
   961→    process.exit(1);
   962→  }
   963→  const chunks: Buffer[] = [];
   964→  for await (const chunk of process.stdin) chunks.push(chunk as Buffer);
   965→  return Buffer.concat(chunks).toString("utf8");
   966→}
   967→
   968→// ─── CLI ──────────────────────────────────────────────────────────────────────
   969→
   970→async function main(): Promise<void> {
   971→  const config = loadConfig();
   972→
   973→  const defaultEventsPath = config.repository
   974→    ? join(expandHome(config.repository), "events.ndjson")
   975→    : "~/.claude/events.ndjson";
   976→  const defaultSessionsPath = config.repository
   977→    ? join(expandHome(config.repository), "sessions.md")
   978→    : "~/.claude/sessions.md";
   979→
   980→  const program = new Command();
   981→
   982→  program
   983→    .name("claude-hook-handler")
   984→    .description(
   985→      "Stdin hook handler for Claude Code's settings-based hook system.\n" +
   986→        "Maintains a live markdown sessions table and writes a JSON response to stdout.",
   987→    )
   988→    .version("1.0.0");
   989→
   990→  // ── reconstruct subcommand ───────────────────────────────────────────────
   991→  program
   992→    .command("reconstruct")
   993→    .description(
   994→      "Rebuild markdown session files from the NDJSON event log.\n" +
   995→        "Clears existing markdown output and replays all recorded events.",
   996→    )
   997→    .option(
   998→      "--events <file>",
   999→      "NDJSON event log to read",
  1000→      defaultEventsPath,
  1001→    )
  1002→    .option(
  1003→      "-s, --sessions <file>",
  1004→      "Markdown sessions table to write",
  1005→      defaultSessionsPath,
  1006→    )
  1007→    .option(
  1008→      "--state <file>",
  1009→      "JSON state file to write",
  1010→      "~/.claude/sessions-state.json",
  1011→    )
  1012→    .option(
  1013→      "--max-log-lines <n>",
  1014→      "Rotate session log files after this many lines (0 to disable)",
  1015→      (v: string) => parseInt(v, 10),
  1016→      1000,
  1017→    )
  1018→    .action(async (opts: {
  1019→      events: string;
  1020→      sessions: string;
  1021→      state: string;
  1022→      maxLogLines: number;
  1023→    }) => {
  1024→      await runReconstruct(opts.events, opts.sessions, opts.state, opts.maxLogLines);
  1025→    });
  1026→
  1027→  // ── default: stdin hook handler ──────────────────────────────────────────
  1028→  program
  1029→    .option(
  1030→      "--events <file>",
  1031→      "Primary NDJSON event log (written before markdown, enables reconstruction)",
  1032→      defaultEventsPath,
  1033→    )
  1034→    .option(
  1035→      "-s, --sessions <file>",
  1036→      "Markdown sessions table to maintain",
  1037→      defaultSessionsPath,
  1038→    )
  1039→    .option(
  1040→      "--state <file>",
  1041→      "JSON state file for session persistence",
  1042→      "~/.claude/sessions-state.json",
  1043→    )
  1044→    .option(
  1045→      "-b, --block <pattern>",
  1046→      "Regex of tool names to block (repeatable, PreToolUse only)",
  1047→      (v: string, acc: string[]) => [...acc, v],
  1048→      [] as string[],
  1049→    )
  1050→    .option(
  1051→      "--block-reason <reason>",
  1052→      "Message sent to Claude when a tool is blocked",
  1053→      "Blocked by claude-hook-handler",
  1054→    )
  1055→    .option(
  1056→      "--no-summary",
  1057→      "Skip AI summarisation, use truncated prompt text instead",
  1058→    )
  1059→    .option(
  1060→      "--max-log-lines <n>",
  1061→      "Rotate session log files after this many lines (0 to disable)",
  1062→      (v: string) => parseInt(v, 10),
  1063→      1000,
  1064→    )
  1065→    .option("--quiet", "Suppress stderr output")
  1066→    .action(async () => {
  1067→      const opts = program.opts<{
  1068→        events: string;
  1069→        sessions: string;
  1070→        state: string;
  1071→        block: string[];
  1072→        blockReason: string;
  1073→        summary: boolean; // commander sets this from --no-summary
  1074→        maxLogLines: number;
  1075→        quiet?: boolean;
  1076→      }>();
  1077→
  1078→      const eventsPath = expandHome(opts.events);
  1079→      const sessionsPath = expandHome(opts.sessions);
  1080→      const statePath = expandHome(opts.state);
  1081→      const blockPatterns = opts.block.map((p) => new RegExp(p));
  1082→      const noSummary = !opts.summary;
  1083→
  1084→      // Read stdin
  1085→      let raw: string;
  1086→      try {
  1087→        raw = await readStdin();
  1088→      } catch (err) {
  1089→        process.stderr.write(`claude-hook-handler: failed to read stdin: ${err}\n`);
  1090→        process.exit(1);
  1091→      }
  1092→
  1093→      let input: HookInput;
  1094→      try {
  1095→        input = JSON.parse(raw) as HookInput;
  1096→      } catch {
  1097→        process.stderr.write(
  1098→          `claude-hook-handler: invalid JSON on stdin:\n${raw.slice(0, 200)}\n`,
  1099→        );
  1100→        process.exit(1);
  1101→      }
  1102→
  1103→      const blocked = shouldBlock(input, blockPatterns);
  1104→
  1105→      if (input.hook_event_name !== "Setup") {
  1106→        try {
