function writeEventLog(
  eventsPath: string,
  input: HookInput,
  blocked: boolean,
  state: State,
): void {
  const absPath = expandHome(eventsPath);
  mkdirSync(dirname(absPath), { recursive: true });

  const record: EventRecord = {
    timestamp: new Date().toISOString(),
    event: input.hook_event_name,
    blocked,
    data: input,
  };

  if (input.hook_event_name === "UserPromptSubmit") {
    const session = state.sessions[input.session_id];
    if (session?.summary !== undefined) record.summary = session.summary;
    if (session?.keywords !== undefined) record.keywords = session.keywords;
  }

  appendFileSync(absPath, JSON.stringify(record) + "\n", "utf8");
}
```

**Key points:**
- Writes one JSON object per line (NDJSON format)
- For `UserPromptSubmit` events, embeds the computed `summary` and `keywords` from state
- This makes the log self-contained for reconstruction without re-running AI

