content.content:
     1→#!/usr/bin/env node
     2→/**
     3→ * Claude Code stdin hook handler.
     4→ *
     5→ * Reads a hook event from stdin, maintains a markdown sessions table, and
     6→ * writes a JSON response to stdout.
     7→ *
     8→ * Configure in ~/.claude/settings.json:
     9→ *
    10→ *   {
    11→ *     "hooks": {
    12→ *       "PreToolUse": [{
    13→ *         "matcher": ".*",
    14→ *         "hooks": [{ "type": "command", "command": "claude-hook-handler --sessions ~/.claude/sessions.md" }]
    15→ *       }],
    16→ *       ...
    17→ *     }
    18→ *   }
    19→ */
    20→import Anthropic from "@anthropic-ai/sdk";
    21→import {
    22→  readFileSync,
    23→  writeFileSync,
    24→  appendFileSync,
    25→  existsSync,
    26→  mkdirSync,
    27→  renameSync,
    28→  readdirSync,
    29→  unlinkSync,
    30→} from "fs";
    31→import { dirname, join, resolve, basename } from "path";
    32→import { homedir } from "os";
    33→import { execSync, spawnSync } from "child_process";
    34→import { Command } from "commander";
    35→import type {
    36→  HookInput,
    37→  SyncHookJSONOutput,
    38→  PreToolUseHookInput,
    39→  PostToolUseHookInput,
    40→  PostToolUseFailureHookInput,
    41→  SubagentStartHookInput,
    42→} from "@anthropic-ai/claude-agent-sdk";
    43→
    44→// ─── Path helpers ─────────────────────────────────────────────────────────────
    45→
    46→function expandHome(p: string): string {
    47→  return p.startsWith("~/") ? join(homedir(), p.slice(2)) : resolve(p);
    48→}
    49→
    50→// ─── Config file ──────────────────────────────────────────────────────────────
    51→
    52→const CONFIG_PATH = join(homedir(), ".claude", "hook-handler.json");
    53→
    54→interface Config {
    55→  anthropicApiKey?: string;
    56→  /**
    57→   * Path to a git repository where session logs are committed.
    58→   * When set, sessions.md and the sessions/ folder are stored inside this
    59→   * directory instead of the default ~/.claude location.
    60→   * The --sessions CLI flag still overrides this value.
    61→   *
    62→   * Example: { "repository": "~/notes/claude-sessions" }
    63→   */
    64→  repository?: string;
    65→}
    66→
    67→function loadConfig(): Config {
    68→  try {
    69→    const raw = readFileSync(CONFIG_PATH, "utf8");
    70→    const config = JSON.parse(raw) as Config;
    71→    if (config.anthropicApiKey && !process.env.ANTHROPIC_API_KEY) {
    72→      process.env.ANTHROPIC_API_KEY = config.anthropicApiKey;
    73→    }
    74→    return config;
    75→  } catch {
    76→    // Config file is optional — no-op if missing or unreadable
    77→    return {};
    78→  }
    79→}
    80→
    81→// ─── Git user ─────────────────────────────────────────────────────────────────
    82→
    83→interface GitUser {
    84→  name?: string;
    85→  email?: string;
    86→}
    87→
    88→function gitUser(): GitUser {
    89→  const get = (key: string): string | undefined => {
    90→    try {
    91→      return execSync(`git config --global ${key}`, {
    92→        encoding: "utf8",
    93→        stdio: ["ignore", "pipe", "ignore"],
    94→      }).trim() || undefined;
    95→    } catch { return undefined; }
    96→  };
    97→  return { name: get("user.name"), email: get("user.email") };
    98→}
    99→
   100→// ─── Git repo detection ───────────────────────────────────────────────────────
   101→
   102→interface RepoInfo {
   103→  repoRoot: string;
   104→  repoName: string;
   105→}
   106→
   107→function detectRepo(cwd: string): RepoInfo | undefined {
   108→  try {
   109→    const root = execSync("git rev-parse --show-toplevel", {
   110→      cwd,
   111→      encoding: "utf8",
   112→      stdio: ["ignore", "pipe", "ignore"],
   113→    }).trim();
   114→    return { repoRoot: root, repoName: basename(root) };
   115→  } catch {
   116→    return undefined;
   117→  }
   118→}
   119→
   120→// ─── Session state ────────────────────────────────────────────────────────────
   121→
   122→interface SessionRecord {
   123→  sessionId: string;
   124→  startedAt: string;
   125→  updatedAt: string;
   126→  cwd: string;
   127→  repoRoot?: string;
   128→  repoName?: string;
   129→  parentSessionId?: string;
   130→  gitUserName?: string;
   131→  gitUserEmail?: string;
   132→  prompt?: string;
   133→  summary?: string;
   134→  keywords?: string[];
   135→}
   136→
   137→interface PendingToolUse {
   138→  tool_use_id: string;
   139→  tool_name: string;
   140→  tool_input?: unknown;
   141→  startedAt: string; // pre-formatted timestamp
   142→}
   143→
   144→// ─── Event record (NDJSON primary store) ──────────────────────────────────────
   145→
   146→interface EventRecord {
   147→  timestamp: string;
   148→  event: string;
   149→  blocked: boolean;
   150→  data: HookInput;
   151→  // Derived fields stored for reconstruction without re-running AI
   152→  summary?: string;
   153→  keywords?: string[];
   154→}
   155→
   156→interface State {
   157→  sessions: Record<string, SessionRecord>;
   158→  // Maps agent_id → parent session_id so we can link child SessionStart events
   159→  agentParents: Record<string, string>;
   160→  // Maps tool_use_id → stashed PreToolUse data, cleared on PostToolUse
   161→  pendingToolUses: Record<string, PendingToolUse>;
   162→}
   163→
   164→function readState(statePath: string): State {
   165→  try {
   166→    const s = JSON.parse(readFileSync(statePath, "utf8")) as Partial<State>;
   167→    return {
   168→      sessions: s.sessions ?? {},
   169→      agentParents: s.agentParents ?? {},
   170→      pendingToolUses: s.pendingToolUses ?? {},
   171→    };
   172→  } catch {
   173→    return { sessions: {}, agentParents: {}, pendingToolUses: {} };
   174→  }
   175→}
   176→
   177→function writeState(statePath: string, state: State): void {
   178→  mkdirSync(dirname(statePath), { recursive: true });
   179→  const tmp = statePath + ".tmp";
   180→  writeFileSync(tmp, JSON.stringify(state, null, 2), "utf8");
   181→  renameSync(tmp, statePath); // atomic on same filesystem
   182→}
   183→
   184→// ─── Markdown rendering ───────────────────────────────────────────────────────
   185→
   186→function fmt(iso: string): string {
   187→  const d = new Date(iso);
   188→  const dd  = String(d.getDate()).padStart(2, "0");
   189→  const mm  = String(d.getMonth() + 1).padStart(2, "0");
   190→  const yy  = String(d.getFullYear()).slice(2);
   191→  const hh  = String(d.getHours()).padStart(2, "0");
   192→  const min = String(d.getMinutes()).padStart(2, "0");
   193→  return `${dd}/${mm}/${yy} ${hh}:${min}`;
   194→}
   195→
   196→function escapeCell(s: string): string {
   197→  return s.replace(/\|/g, "\\|").replace(/\n/g, " ");
   198→}
   199→
   200→function renderMarkdown(state: State): string {
   201→  const sessions = Object.values(state.sessions).sort((a, b) =>
   202→    b.updatedAt.localeCompare(a.updatedAt),
   203→  );
   204→
   205→  const updatedAt = `${fmt(new Date().toISOString())} UTC`;
   206→
   207→  if (sessions.length === 0) {
   208→    return (
   209→      `# Claude Code Sessions\n\n` +
   210→      `*No active sessions.*\n\n` +
   211→      `*Last updated: ${updatedAt}*\n`
   212→    );
   213→  }
   214→
   215→  const header = "| Session ID | User | Repo | Summary | Keywords | Started | Last Updated |";
   216→  const divider = "|---|---|---|---|---|---|---|";
   217→  const rows = sessions.map((s) => {
   218→    const id = `[\`${s.sessionId.slice(0, 8)}…\`](sessions/${s.sessionId}.md)`;
   219→    const user = escapeCell(
   220→      s.gitUserName && s.gitUserEmail ? `${s.gitUserName} <${s.gitUserEmail}>`
   221→      : s.gitUserName ?? s.gitUserEmail ?? "",
   222→    );
   223→    const repo = escapeCell(s.repoName ?? s.cwd.split("/").pop() ?? s.cwd);
   224→    const summary = escapeCell(
   225→      s.summary ?? s.prompt?.slice(0, 80) ?? "*waiting for prompt…*",
   226→    );
   227→    const keywords = s.keywords?.length
   228→      ? s.keywords.map((k) => `\`${escapeCell(k)}\``).join(" ")
   229→      : "";
   230→    return `| ${id} | ${user} | ${repo} | ${summary} | ${keywords} | ${fmt(s.startedAt)} | ${fmt(s.updatedAt)} |`;
   231→  });
   232→
   233→  return [
   234→    "# Claude Code Sessions",
   235→    "",
   236→    header,
   237→    divider,
   238→    ...rows,
   239→    "",
   240→    `*Last updated: ${updatedAt}*`,
   241→    "",
   242→  ].join("\n");
   243→}
   244→
   245→function writeMarkdown(sessionsPath: string, state: State): void {
   246→  mkdirSync(dirname(sessionsPath), { recursive: true });
   247→  const tmp = sessionsPath + ".tmp";
   248→  writeFileSync(tmp, renderMarkdown(state), "utf8");
   249→  renameSync(tmp, sessionsPath);
   250→}
   251→
   252→// ─── Per-session event log ────────────────────────────────────────────────────
   253→
   254→// Always omit — structural noise with no reader value
   255→const SKIP_COMMON = new Set([
   256→  "session_id", "hook_event_name", "transcript_path", "tool_use_id",
   257→]);
   258→// Also omit for collapsed events (same for every tool call — not useful per-event)
   259→const SKIP_NOISE = new Set([...SKIP_COMMON, "cwd", "permission_mode"]);
   260→
   261→const IMPORTANT_EVENTS = new Set([
   262→  "UserPromptSubmit", "Stop", "SessionEnd",
   263→]);
   264→
   265→const SKIP_EVENTS = new Set([
   266→  "SessionStart",
   267→]);
   268→
   269→/** Extract a short hint string from tool_input for the <summary> line. */
   270→function toolSummaryHint(toolName: string, toolInput: unknown): string {
   271→  if (!toolInput || typeof toolInput !== "object") return "";
   272→  const inp = toolInput as Record<string, unknown>;
   273→  const str = (k: string): string | undefined =>
   274→    typeof inp[k] === "string" ? String(inp[k]) : undefined;
   275→  switch (toolName) {
   276→    case "Read":      return str("file_path") ?? "";
   277→    case "Write":     return str("file_path") ?? "";
   278→    case "Edit":      return str("file_path") ?? "";
   279→    case "Bash":      return (str("command") ?? "").slice(0, 70);
   280→    case "Glob":      return str("pattern") ?? "";
   281→    case "Grep":      return str("pattern") ?? "";
   282→    case "WebFetch":  return str("url") ?? "";
   283→    case "WebSearch": return str("query") ?? "";
   284→    default:          return "";
   285→  }
   286→}
   287→
   288→/** Render fields for an event, skipping the given skip-set. */
   289→function renderFields(
   290→  input: HookInput,
   291→  skip: Set<string>,
   292→  childLogRelPath?: string,
   293→): string[] {
   294→  const lines: string[] = [];
   295→  for (const [key, value] of Object.entries(input)) {
   296→    if (skip.has(key) || value === undefined) continue;
   297→    if (key === "prompt" || key === "message" || key === "last_assistant_message") {
   298→      lines.push(`**${key}:**`, "");
   299→      for (const line of String(value).split("\n")) lines.push(`> ${line}`);
   300→      lines.push("");
   301→    } else if (key === "tool_input" || key === "tool_response") {
   302→      const s = JSON.stringify(value, null, 2);
   303→      lines.push(`**${key}:**`, "```json", s.length > 600 ? s.slice(0, 600) + "\n…" : s, "```", "");
   304→    } else if (key === "agent_id" && childLogRelPath) {
   305→      lines.push(`- **${key}:** [\`${String(value)}\`](${childLogRelPath})`);
   306→    } else {
   307→      lines.push(`- **${key}:** \`${String(value)}\``);
   308→    }
   309→  }
   310→  return lines;
   311→}
   312→
   313→/** Important events: H2 heading, full field list, horizontal rule. */
   314→function formatImportantEvent(input: HookInput): string {
   315→  const ts = fmt(new Date().toISOString());
   316→  const name = input.hook_event_name;
   317→  const sym = EVENT_SYMBOL[name] ?? "◆";
   318→  const fields = renderFields(input, SKIP_COMMON);
   319→  return [`## ${sym} ${name}`, "", `<small>${ts}</small>`, "", ...fields, "---", ""].join("\n");
   320→}
   321→
   322→/** UserPromptSubmit: "<User> prompted:" followed by the prompt as a blockquote. */
   323→function formatPromptEvent(input: HookInput, rec: SessionRecord | undefined): string {
   324→  const ts = fmt(new Date().toISOString());
   325→  const user = rec?.gitUserName ?? rec?.gitUserEmail ?? "User";
   326→  const prompt = "prompt" in input ? String(input.prompt) : "";
   327→  const lines: string[] = [`## → **${user} prompted:**`, "", `<small>${ts}</small>`, ""];
   328→  for (const line of prompt.split("\n")) lines.push(`> ${line}`);
   329→  lines.push("", "---", "");
   330→  return lines.join("\n");
   331→}
   332→
   333→/** Stop / Notification: "Claude wrote:" followed by the message as a blockquote. */
   334→function formatClaudeMessageEvent(input: HookInput): string {
   335→  const ts = fmt(new Date().toISOString());
   336→  const sym = EVENT_SYMBOL[input.hook_event_name] ?? "◆";
   337→  const message =
   338→    "last_assistant_message" in input && input.last_assistant_message
   339→      ? String(input.last_assistant_message)
   340→      : "message" in input && input.message
   341→      ? String(input.message)
   342→      : "";
   343→
   344→  if (!message) return formatImportantEvent(input);
   345→
   346→  const lines: string[] = [`## ${sym} **Claude wrote:**`, "", `<small>${ts}</small>`, ""];
   347→  for (const line of message.split("\n")) lines.push(`> ${line}`);
   348→  lines.push("", "---", "");
   349→  return lines.join("\n");
   350→}
   351→
   352→/** Non-critical events: collapsed <details> block. */
   353→function formatCollapsibleEvent(input: HookInput, childLogRelPath?: string): string {
   354→  const ts = fmt(new Date().toISOString());
   355→  const name = input.hook_event_name;
   356→  const sym = EVENT_SYMBOL[name] ?? "◆";
   357→  const fields = renderFields(input, SKIP_NOISE, childLogRelPath);
   358→  return [
   359→    `<details>`,
   360→    `<summary><small>${name}</small></summary>`,
   361→    "",
   362→    `<small>${ts}</small>`,
   363→    "",
   364→    ...fields,
   365→    `</details>`,
   366→    "",
   367→    "",
   368→  ].join("\n");
   369→}
   370→
   371→/** Merged Pre+PostToolUse: collapsed <details> with success/failure indicator. */
   372→function formatMergedToolUse(
   373→  pending: PendingToolUse,
   374→  post: PostToolUseHookInput | PostToolUseFailureHookInput,
   375→): string {
   376→  const failed = post.hook_event_name === "PostToolUseFailure";
   377→  const statusSym = failed ? "✗" : "✓";
   378→  const hint = toolSummaryHint(pending.tool_name, pending.tool_input);
   379→  const hintStr = hint ? ` · \`${hint.replace(/`/g, "'").replace(/\s+/g, " ")}\`` : "";
   380→  const endTs = fmt(new Date().toISOString());
   381→
   382→  const lines: string[] = [
   383→    `<details>`,
   384→    `<summary><small>${statusSym} ${pending.tool_name}${hintStr}</small></summary>`,
   385→    "",
   386→    `<small>${pending.startedAt} → ${endTs}</small>`,
   387→    "",
   388→  ];
   389→
   390→  if (pending.tool_input !== undefined) {
   391→    const s = JSON.stringify(pending.tool_input, null, 2);
   392→    lines.push("**input:**", "```json", s.length > 600 ? s.slice(0, 600) + "\n…" : s, "```", "");
   393→  }
   394→
   395→  if (failed && "error" in post && post.error) {
   396→    lines.push(`**error:** \`${String(post.error)}\``, "");
   397→  } else if ("tool_response" in post && post.tool_response !== undefined) {
   398→    const s =
   399→      typeof post.tool_response === "string"
   400→        ? post.tool_response
   401→        : JSON.stringify(post.tool_response, null, 2);
   402→    lines.push("**output:**", "```", s.length > 400 ? s.slice(0, 400) + "\n…" : s, "```", "");
   403→  }
   404→
   405→  lines.push(`</details>`, "", "");
   406→  return lines.join("\n");
   407→}
   408→
   409→function sessionLogPath(sessionsPath: string, sessionId: string): string {
   410→  return join(dirname(sessionsPath), "sessions", `${sessionId}.md`);
   411→}
   412→
   413→// ─── Log rotation ─────────────────────────────────────────────────────────────
   414→
   415→function archiveTimestamp(): string {
   416→  const d = new Date();
   417→  return (
   418→    String(d.getFullYear()) +
   419→    String(d.getMonth() + 1).padStart(2, "0") +
   420→    String(d.getDate()).padStart(2, "0") +
   421→    "-" +
   422→    String(d.getHours()).padStart(2, "0") +
   423→    String(d.getMinutes()).padStart(2, "0")
   424→  );
   425→}
   426→
   427→/**
   428→ * If `logPath` exceeds `maxLines` lines, rename it to a timestamped archive,
   429→ * then write a fresh file containing only the header (with an "← prev" link).
   430→ * Returns the archive path if rotation happened, undefined otherwise.
   431→ */
   432→function rotateSessionLog(logPath: string, maxLines: number): string | undefined {
   433→  if (!existsSync(logPath)) return undefined;
   434→
   435→  const content = readFileSync(logPath, "utf8");
   436→  if (content.split("\n").length <= maxLines) return undefined;
   437→
   438→  // Build archive filename next to the current file
   439→  const dir = dirname(logPath);
   440→  const base = basename(logPath, ".md");
   441→  const archiveName = `${base}-${archiveTimestamp()}.md`;
   442→  const archivePath = join(dir, archiveName);
   443→
   444→  // Rename current file → archive
   445→  renameSync(logPath, archivePath);
   446→
   447→  // Append a forward link to the bottom of the archived file
   448→  const nextName = basename(logPath);
   449→  appendFileSync(archivePath, `\n---\n\n<small>[→ next](${nextName})</small>\n`, "utf8");
   450→
   451→  // Extract header: everything before the first event entry
   452→  const firstEventIdx = content.search(/^(?:## |<details>)/m);
   453→  let header = firstEventIdx !== -1 ? content.slice(0, firstEventIdx) : content;
   454→
   455→  // Inject / update the "← prev" link next to the session ID in the <sub> line
   456→  const prevLink = `[← prev](${archiveName})`;
   457→  if (header.includes("[← prev]")) {
   458→    // Update existing link to point to the new archive
   459→    header = header.replace(/\[← prev\]\([^)]*\)/, prevLink);
   460→  } else if (header.includes("<sub>")) {
   461→    // Insert after the backtick-wrapped session ID
   462→    header = header.replace(/(<sub>)(`[^`]+`)/, `$1$2 · ${prevLink}`);
   463→  } else {
   464→    // Fallback for bare initial header (pre-UserPromptSubmit)
   465→    header = header.replace(
   466→      /^(# Session `[^`]+`\n\n)/m,
   467→      `$1<small>${prevLink}</small>\n\n`,
   468→    );
   469→  }
   470→
   471→  writeFileSync(logPath, header, "utf8");
   472→  return archivePath;
   473→}
   474→
   475→function updateLogHeader(logPath: string, rec: SessionRecord): void {
   476→  const content = readFileSync(logPath, "utf8");
   477→
   478→  // Build the new header: AI summary as the H1, session ID + user in small text beneath
   479→  const title = rec.summary ?? `Session \`${rec.sessionId}\``;
   480→  const keywordsLine = rec.keywords?.length
   481→    ? `**Keywords:** ${rec.keywords.map((k) => `\`${k}\``).join(" ")}`
   482→    : "";
   483→
   484→  const userPart = rec.gitUserName && rec.gitUserEmail
   485→    ? ` · ${rec.gitUserName} &lt;${rec.gitUserEmail}&gt;`
   486→    : rec.gitUserName ? ` · ${rec.gitUserName}`
   487→    : rec.gitUserEmail ? ` · ${rec.gitUserEmail}`
   488→    : "";
   489→  const headerParts = [`# ${title}`, "", `<sub>\`${rec.sessionId}\`${userPart}</sub>`, ""];
   490→  if (keywordsLine) headerParts.push(keywordsLine, "");
   491→  const newHeader = headerParts.join("\n");
   492→
   493→  // Replace everything from the start of file up to the first event entry.
   494→  // Events start with ## , ### , or <details>.
   495→  const firstEventIdx = content.search(/^(?:#{2,3} |<details>)/m);
   496→  const body = firstEventIdx !== -1 ? content.slice(firstEventIdx) : "";
   497→  writeFileSync(logPath, newHeader + "\n" + body, "utf8");
   498→}
   499→
   500→function appendSessionLog(sessionsPath: string, input: HookInput, state: State, maxLogLines: number): string[] {
   501→  const logPath = sessionLogPath(sessionsPath, input.session_id);
   502→  mkdirSync(dirname(logPath), { recursive: true });
   503→
   504→  if (!existsSync(logPath)) {
   505→    writeFileSync(logPath, `# Session \`${input.session_id}\`\n\n`, "utf8");
   506→  }
   507→
   508→  // Patch the file header with summary + keywords once we have them
   509→  if (input.hook_event_name === "UserPromptSubmit") {
   510→    const rec = state.sessions[input.session_id];
   511→    if (rec) updateLogHeader(logPath, rec);
   512→  }
   513→
   514→  // ── Events to skip entirely ───────────────────────────────────────────────
   515→  if (SKIP_EVENTS.has(input.hook_event_name)) {
   516→    return [];
   517→  }
   518→
   519→  // ── PreToolUse: stash and write nothing yet ───────────────────────────────
   520→  if (input.hook_event_name === "PreToolUse") {
   521→    const pre = input as PreToolUseHookInput;
   522→    state.pendingToolUses[pre.tool_use_id] = {
   523→      tool_use_id: pre.tool_use_id,
   524→      tool_name: pre.tool_name,
   525→      tool_input: pre.tool_input,
   526→      startedAt: fmt(new Date().toISOString()),
   527→    };
   528→    return []; // nothing written to disk yet
   529→  }
   530→
   531→  // ── Log rotation (before any write) ──────────────────────────────────────
   532→  const rotatedPaths: string[] = [];
   533→  if (maxLogLines > 0) {
   534→    const archived = rotateSessionLog(logPath, maxLogLines);
   535→    if (archived) rotatedPaths.push(archived);
   536→  }
   537→
   538→  // ── PostToolUse / PostToolUseFailure: merge with stashed Pre ─────────────
   539→  if (
   540→    input.hook_event_name === "PostToolUse" ||
   541→    input.hook_event_name === "PostToolUseFailure"
   542→  ) {
   543→    const post = input as PostToolUseHookInput | PostToolUseFailureHookInput;
   544→    const pending = state.pendingToolUses[post.tool_use_id];
   545→    if (pending) {
   546→      delete state.pendingToolUses[post.tool_use_id];
   547→      appendFileSync(logPath, formatMergedToolUse(pending, post), "utf8");
   548→    } else {
   549→      // No matching Pre (e.g. state was cleared) — render as collapsible fallback
   550→      appendFileSync(logPath, formatCollapsibleEvent(input), "utf8");
   551→    }
   552→    return [...rotatedPaths, logPath];
   553→  }
   554→
   555→  // ── SubagentStart: create child log file ──────────────────────────────────
   556→  const changedPaths: string[] = [...rotatedPaths];
   557→  let childLogRelPath: string | undefined;
   558→
   559→  if (input.hook_event_name === "SubagentStart") {
   560→    const { agent_id, agent_type } = input as SubagentStartHookInput;
   561→    const childPath = sessionLogPath(sessionsPath, agent_id);
   562→    mkdirSync(dirname(childPath), { recursive: true });
   563→    if (!existsSync(childPath)) {
   564→      const parentLink = `[\`${input.session_id.slice(0, 8)}…\`](${input.session_id}.md)`;
   565→      writeFileSync(
   566→        childPath,
   567→        `# Subagent Session \`${agent_id}\`\n\n` +
   568→        `**Parent:** ${parentLink}  \n` +
   569→        `**Type:** \`${agent_type}\`\n\n`,
   570→        "utf8",
   571→      );
   572→      changedPaths.push(childPath);
   573→    }
   574→    childLogRelPath = `${agent_id}.md`;
   575→  }
   576→
   577→  // ── Important events: prominent H2 rendering ──────────────────────────────
   578→  if (input.hook_event_name === "UserPromptSubmit") {
   579→    appendFileSync(logPath, formatPromptEvent(input, state.sessions[input.session_id]), "utf8");
   580→  } else if (input.hook_event_name === "Stop" || input.hook_event_name === "Notification") {
   581→    appendFileSync(logPath, formatClaudeMessageEvent(input), "utf8");
   582→  } else if (IMPORTANT_EVENTS.has(input.hook_event_name)) {
   583→    appendFileSync(logPath, formatImportantEvent(input), "utf8");
   584→  } else {
   585→    // ── Everything else: collapsed ────────────────────────────────────────────
   586→    appendFileSync(logPath, formatCollapsibleEvent(input, childLogRelPath), "utf8");
   587→  }
   588→
   589→  changedPaths.push(logPath);
   590→  return changedPaths;
   591→}
   592→
   593→// ─── Git history ──────────────────────────────────────────────────────────────
   594→
   595→function ensureRepo(dir: string, sessionsFilename: string): void {
   596→  try {
   597→    execSync("git rev-parse --git-dir", { cwd: dir, stdio: "ignore" });
   598→  } catch {
   599→    execSync("git init", { cwd: dir, stdio: "ignore" });
   600→  }
   601→  // Always keep gitignore up to date — may need to add sessions/ on upgrade
   602→  const gitignore = join(dir, ".gitignore");
   603→  const desired =
   604→    `# Managed by claude-hook-handler\n` +
   605→    `*\n!.gitignore\n!${sessionsFilename}\n!sessions/\n!sessions/*.md\n`;
   606→  try {
   607→    if (readFileSync(gitignore, "utf8") !== desired) writeFileSync(gitignore, desired, "utf8");
   608→  } catch {
   609→    writeFileSync(gitignore, desired, "utf8");
   610→  }
   611→}
   612→
   613→function commitFiles(sessionsPath: string, paths: string[], message: string): void {
   614→  const dir = dirname(sessionsPath);
   615→  ensureRepo(dir, basename(sessionsPath));
   616→
   617→  for (const p of paths) spawnSync("git", ["add", p], { cwd: dir });
   618→
   619→  const diff = spawnSync("git", ["diff", "--cached", "--quiet"], { cwd: dir });
   620→  if (diff.status === 0) return;
   621→
   622→  spawnSync(
   623→    "git",
   624→    [
   625→      "-c", "user.name=claude-hook-handler",
   626→      "-c", "user.email=noreply@localhost",
   627→      "commit", "-m", message,
   628→    ],
   629→    { cwd: dir },
   630→  );
   631→}
   632→
   633→function buildCommitMessage(input: HookInput, state: State): string {
   634→  const id = input.session_id.slice(0, 8);
   635→  switch (input.hook_event_name) {
   636→    case "SessionStart": {
   637→      const rec = state.sessions[input.session_id];
   638→      const repo = rec?.repoName ? ` (${rec.repoName})` : "";
   639→      return `session started: ${id}${repo}`;
   640→    }
   641→    case "UserPromptSubmit": {
   642→      const rec = state.sessions[input.session_id];
   643→      const summary = rec?.summary ?? rec?.prompt?.slice(0, 60) ?? "";
   644→      return `session prompt: ${id}: ${summary}`;
   645→    }
   646→    case "SessionEnd":
   647→      return `session ended: ${id}`;
   648→    default: {
   649→      const count = Object.keys(state.sessions).length;
   650→      return `sessions: ${count} active`;
   651→    }
   652→  }
   653→}
   654→
   655→// ─── Prompt summarisation ─────────────────────────────────────────────────────
   656→
   657→interface PromptAnalysis {
   658→  summary: string;
   659→  keywords: string[];
   660→}
   661→
   662→async function analyse(prompt: string): Promise<PromptAnalysis> {
   663→  if (!process.env.ANTHROPIC_API_KEY) {
   664→    return truncateAnalysis(prompt);
   665→  }
   666→  try {
   667→    const client = new Anthropic();
   668→    const response = await client.messages.create({
   669→      model: "claude-haiku-4-5",
   670→      max_tokens: 120,
   671→      messages: [
   672→        {
   673→          role: "user",
   674→          content:
   675→            `Analyse the following user prompt. Reply with a JSON object only — no prose, no code fences.\n` +
   676→            `{\n` +
   677→            `  "summary": "<one sentence, 10 words max, no trailing punctuation>",\n` +
   678→            `  "keywords": ["<3-6 keywords: named entities, tools, concepts, actions>"]\n` +
   679→            `}\n\nPrompt:\n${prompt}`,
   680→        },
   681→      ],
   682→    });
   683→    const block = response.content[0];
   684→    if (block?.type === "text") {
   685→      // Strip markdown code fences in case the model wraps its JSON
   686→      const raw = block.text.trim()
   687→        .replace(/^```(?:json)?\s*/i, "")
   688→        .replace(/\s*```$/, "");
   689→      const parsed = JSON.parse(raw) as Partial<PromptAnalysis>;
   690→      return {
   691→        summary: String(parsed.summary ?? "").replace(/[.!?]$/, ""),
   692→        keywords: Array.isArray(parsed.keywords) ? parsed.keywords.map(String) : [],
   693→      };
   694→    }
   695→  } catch {
   696→    // fall through
   697→  }
   698→  return truncateAnalysis(prompt);
   699→}
   700→
   701→function truncateAnalysis(prompt: string): PromptAnalysis {
   702→  const firstLine = prompt.split("\n")[0]?.trim() ?? prompt;
   703→  return {
   704→    summary: firstLine.length > 80 ? firstLine.slice(0, 77) + "…" : firstLine,
   705→    keywords: [],
   706→  };
   707→}
   708→
   709→// ─── State mutation per event ─────────────────────────────────────────────────
   710→
   711→async function applyEvent(
   712→  state: State,
   713→  input: HookInput,
   714→  noSummary: boolean,
   715→  precomputed?: { summary: string; keywords: string[] },
   716→): Promise<void> {
   717→  const { session_id, hook_event_name, cwd } = input;
   718→  const now = new Date().toISOString();
   719→
   720→  switch (hook_event_name) {
   721→    case "SessionStart": {
   722→      const repo = detectRepo(cwd);
   723→      const parentSessionId = state.agentParents[session_id];
   724→      const user = gitUser();
   725→      state.sessions[session_id] = {
   726→        sessionId: session_id,
   727→        startedAt: now,
   728→        updatedAt: now,
   729→        cwd,
   730→        repoRoot: repo?.repoRoot,
   731→        repoName: repo?.repoName,
   732→        parentSessionId,
   733→        gitUserName: user.name,
   734→        gitUserEmail: user.email,
   735→      };
   736→      break;
   737→    }
   738→
   739→    case "SubagentStart": {
   740→      const { agent_id } = input as SubagentStartHookInput;
   741→      state.agentParents[agent_id] = session_id;
   742→      // Touch parent updatedAt
   743→      const existing = state.sessions[session_id];
   744→      if (existing) existing.updatedAt = now;
   745→      break;
   746→    }
   747→
   748→    case "UserPromptSubmit": {
   749→      const prompt = "prompt" in input ? String(input.prompt) : "";
   750→      const existing = state.sessions[session_id];
   751→      const { summary, keywords } = precomputed ?? (noSummary ? truncateAnalysis(prompt) : await analyse(prompt));
   752→      // Detect repo/user now if SessionStart was missed
   753→      const repo = existing?.repoRoot ? undefined : detectRepo(existing?.cwd ?? cwd);
   754→      const user = (existing?.gitUserName ?? existing?.gitUserEmail) ? undefined : gitUser();
   755→      state.sessions[session_id] = {
   756→        sessionId: session_id,
   757→        startedAt: existing?.startedAt ?? now,
   758→        updatedAt: now,
   759→        cwd: existing?.cwd ?? cwd,
   760→        repoRoot: existing?.repoRoot ?? repo?.repoRoot,
   761→        repoName: existing?.repoName ?? repo?.repoName,
   762→        parentSessionId: existing?.parentSessionId,
   763→        gitUserName: existing?.gitUserName ?? user?.name,
   764→        gitUserEmail: existing?.gitUserEmail ?? user?.email,
   765→        prompt,
   766→        summary,
   767→        keywords,
   768→      };
   769→      break;
   770→    }
   771→
   772→    case "SessionEnd": {
   773→      delete state.sessions[session_id];
   774→      break;
   775→    }
   776→
   777→    case "PreToolUse":
   778→      // Don't update sessions table — too frequent, makes updatedAt meaningless
   779→      break;
   780→
   781→    default: {
   782→      // Touch updatedAt for any other event
   783→      const existing = state.sessions[session_id];
   784→      if (existing) {
   785→        existing.updatedAt = now;
   786→      }
   787→      break;
   788→    }
   789→  }
   790→}
   791→
   792→// ─── stderr formatting ────────────────────────────────────────────────────────
   793→
   794→const EVENT_SYMBOL: Record<string, string> = {
   795→  PreToolUse:         "▶",
   796→  PostToolUse:        "✓",
   797→  PostToolUseFailure: "✗",
   798→  SessionStart:       "◉",
   799→  SessionEnd:         "◎",
   800→  Stop:               "■",
   801→  UserPromptSubmit:   "→",
   802→  Notification:       "◆",
   803→  Setup:              "⚙",
   804→  SubagentStart:      "▷",
   805→  SubagentStop:       "◁",
   806→  PermissionRequest:  "?",
   807→  PreCompact:         "⌃",
   808→};
   809→
   810→function formatForStderr(input: HookInput, blocked: boolean): string {
   811→  const ts = new Date().toISOString().replace("T", " ").slice(0, 23);
   812→  const name = input.hook_event_name;
   813→  const sym = EVENT_SYMBOL[name] ?? "◆";
   814→  const blockTag = blocked ? " \x1b[31m[BLOCKED]\x1b[0m" : "";
   815→
   816→  const lines = [`\x1b[1m[${ts}] ${sym} ${name}\x1b[0m${blockTag}`];
   817→
   818→  if ("tool_name" in input)
   819→    lines.push(`  tool:   \x1b[1m${input.tool_name}\x1b[0m`);
   820→  if ("tool_input" in input && input.tool_input !== undefined) {
   821→    const s = JSON.stringify(input.tool_input);
   822→    lines.push(`  input:  ${s.length > 120 ? s.slice(0, 120) + "…" : s}`);
   823→  }
   824→  if ("tool_response" in input && input.tool_response !== undefined) {
   825→    const s = JSON.stringify(input.tool_response);
   826→    lines.push(`  output: ${s.length > 120 ? s.slice(0, 120) + "…" : s}`);
   827→  }
   828→  if ("error" in input && input.error)
   829→    lines.push(`  error:  \x1b[31m${input.error}\x1b[0m`);
   830→  if ("prompt" in input && input.prompt)
   831→    lines.push(`  prompt: ${String(input.prompt).slice(0, 100)}`);
   832→  if ("message" in input && input.message)
   833→    lines.push(`  msg:    ${String(input.message)}`);
   834→  if ("reason" in input && input.reason)
   835→    lines.push(`  reason: ${String(input.reason)}`);
   836→  if ("source" in input && input.source)
   837→    lines.push(`  source: ${String(input.source)}`);
   838→
   839→  lines.push(`  session: \x1b[2m${input.session_id.slice(0, 8)}…\x1b[0m`);
   840→  return lines.join("\n");
   841→}
   842→
   843→// ─── Tool blocking ────────────────────────────────────────────────────────────
   844→
   845→function shouldBlock(input: HookInput, patterns: RegExp[]): boolean {
   846→  if (input.hook_event_name !== "PreToolUse" || patterns.length === 0)
   847→    return false;
   848→  const name = (input as PreToolUseHookInput).tool_name ?? "";
   849→  return patterns.some((re) => re.test(name));
   850→}
   851→
   852→function buildResponse(blocked: boolean, reason: string): SyncHookJSONOutput {
   853→  return blocked ? { decision: "block", reason } : {};
   854→}
   855→
   856→// ─── NDJSON event log (primary store) ────────────────────────────────────────
   857→
   858→/**
   859→ * Append one event record to the NDJSON event log.
   860→ * For UserPromptSubmit, also embeds `summary` and `keywords` from the already-
   861→ * computed session state so the log is self-contained for reconstruction.
   862→ */
   863→function writeEventLog(
   864→  eventsPath: string,
   865→  input: HookInput,
   866→  blocked: boolean,
   867→  state: State,
   868→): void {
   869→  const absPath = expandHome(eventsPath);
   870→  mkdirSync(dirname(absPath), { recursive: true });
   871→
   872→  const record: EventRecord = {
   873→    timestamp: new Date().toISOString(),
   874→    event: input.hook_event_name,
   875→    blocked,
   876→    data: input,
   877→  };
   878→
   879→  if (input.hook_event_name === "UserPromptSubmit") {
   880→    const session = state.sessions[input.session_id];
   881→    if (session?.summary !== undefined) record.summary = session.summary;
   882→    if (session?.keywords !== undefined) record.keywords = session.keywords;
   883→  }
   884→
   885→  appendFileSync(absPath, JSON.stringify(record) + "\n", "utf8");
   886→}
   887→
   888→// ─── Reconstruction ───────────────────────────────────────────────────────────
   889→
   890→/**
   891→ * Replay the NDJSON event log and rebuild all markdown files from scratch.
   892→ * Uses stored summary/keywords from each record; calls AI for any that are missing
   893→ * unless noSummary is true.
   894→ */
   895→async function runReconstruct(
   896→  eventsPath: string,
   897→  sessionsPath: string,
   898→  statePath: string,
   899→  maxLogLines: number,
   900→  noSummary: boolean,
   901→): Promise<void> {
   902→  const absEvents = expandHome(eventsPath);
   903→  if (!existsSync(absEvents)) {
   904→    process.stderr.write(`claude-hook-handler: no event log found at ${absEvents}\n`);
   905→    process.exit(1);
   906→  }
   907→
   908→  // Clear existing markdown output so we start fresh
   909→  const absSessions = expandHome(sessionsPath);
   910→  const sessionsDir = join(dirname(absSessions), "sessions");
   911→  if (existsSync(sessionsDir)) {
   912→    for (const f of readdirSync(sessionsDir)) {
   913→      if (f.endsWith(".md")) unlinkSync(join(sessionsDir, f));
   914→    }
   915→  }
   916→  if (existsSync(absSessions)) unlinkSync(absSessions);
   917→
   918→  const state: State = { sessions: {}, agentParents: {}, pendingToolUses: {} };
   919→  const rawLines = readFileSync(absEvents, "utf8").split("\n");
   920→  const updatedLines: string[] = [];
   921→  let replayed = 0;
   922→  let skipped = 0;
   923→  let filled = 0;
   924→
   925→  for (const line of rawLines) {
   926→    if (!line.trim()) {
   927→      updatedLines.push(line);
   928→      continue;
   929→    }
   930→
   931→    let record: EventRecord;
   932→    try {
   933→      record = JSON.parse(line) as EventRecord;
   934→    } catch {
   935→      skipped++;
   936→      updatedLines.push(line);
   937→      continue;
   938→    }
   939→
   940→    const input = record.data as HookInput;
   941→    if (!input?.hook_event_name || input.hook_event_name === "Setup") {
   942→      updatedLines.push(line);
   943→      continue;
   944→    }
   945→
   946→    const precomputed =
   947→      record.summary !== undefined
   948→        ? { summary: record.summary, keywords: record.keywords ?? [] }
   949→        : undefined;
   950→
   951→    await applyEvent(state, input, noSummary, precomputed);
   952→
   953→    // If AI filled in missing summary/keywords, backfill into the NDJSON record
   954→    if (!precomputed && input.hook_event_name === "UserPromptSubmit") {
   955→      const session = state.sessions[input.session_id];
   956→      if (session?.summary !== undefined) {
   957→        record.summary = session.summary;
   958→        record.keywords = session.keywords ?? [];
   959→        filled++;
   960→        updatedLines.push(JSON.stringify(record));
   961→      } else {
   962→        updatedLines.push(line);
   963→      }
   964→    } else {
   965→      updatedLines.push(line);
   966→    }
   967→
   968→    writeMarkdown(absSessions, state);
   969→    appendSessionLog(absSessions, input, state, maxLogLines);
   970→    replayed++;
   971→  }
   972→
   973→  // Write back NDJSON with any newly computed summaries
   974→  if (filled > 0) {
   975→    writeFileSync(absEvents, updatedLines.join("\n"), "utf8");
   976→    process.stderr.write(`claude-hook-handler reconstruct: filled ${filled} missing summaries\n`);
   977→  }
   978→
   979→  writeState(expandHome(statePath), state);
   980→  process.stderr.write(
   981→    `claude-hook-handler reconstruct: replayed ${replayed} events` +
   982→      (skipped ? `, skipped ${skipped} malformed lines` : "") +
   983→      `\n  sessions → ${absSessions}\n`,
   984→  );
   985→}
   986→
   987→// ─── stdin ────────────────────────────────────────────────────────────────────
   988→
   989→async function readStdin(): Promise<string> {
   990→  if (process.stdin.isTTY) {
   991→    process.stderr.write(
   992→      "claude-hook-handler: no stdin detected.\n" +
   993→        "This program is called by Claude Code hooks, not directly.\n" +
   994→        "Run with --help for configuration instructions.\n",
   995→    );
   996→    process.exit(1);
   997→  }
   998→  const chunks: Buffer[] = [];
   999→  for await (const chunk of process.stdin) chunks.push(chunk as Buffer);
  1000→  return Buffer.concat(chunks).toString("utf8");
  1001→}
  1002→
  1003→// ─── CLI ──────────────────────────────────────────────────────────────────────
  1004→
  1005→async function main(): Promise<void> {
  1006→  const config = loadConfig();
  1007→
  1008→  const defaultEventsPath = config.repository
  1009→    ? join(expandHome(config.repository), "events.ndjson")
  1010→    : "~/.claude/events.ndjson";
  1011→  const defaultSessionsPath = config.repository
  1012→    ? join(expandHome(config.repository), "sessions.md")
  1013→    : "~/.claude/sessions.md";
  1014→
  1015→  const program = new Command();
  1016→
  1017→  program
  1018→    .name("claude-hook-handler")
  1019→    .description(
  1020→      "Stdin hook handler for Claude Code's settings-based hook system.\n" +
  1021→        "Maintains a live markdown sessions table and writes a JSON response to stdout.",
  1022→    )
  1023→    .version("1.0.0")
  1024→    .enablePositionalOptions();
  1025→
  1026→  // ── reconstruct subcommand ───────────────────────────────────────────────
  1027→  program
  1028→    .command("reconstruct")
  1029→    .description(
  1030→      "Rebuild markdown session files from the NDJSON event log.\n" +
  1031→        "Clears existing markdown output and replays all recorded events.",
  1032→    )
  1033→    .option(
  1034→      "--events <file>",
  1035→      "NDJSON event log to read",
  1036→      defaultEventsPath,
  1037→    )
  1038→    .option(
  1039→      "-s, --sessions <file>",
  1040→      "Markdown sessions table to write",
  1041→      defaultSessionsPath,
  1042→    )
  1043→    .option(
  1044→      "--state <file>",
  1045→      "JSON state file to write",
  1046→      "~/.claude/sessions-state.json",
  1047→    )
  1048→    .option(
  1049→      "--max-log-lines <n>",
  1050→      "Rotate session log files after this many lines (0 to disable)",
  1051→      (v: string) => parseInt(v, 10),
  1052→      1000,
  1053→    )
  1054→    .option("--no-summary", "Skip AI summarisation, use truncated prompt text instead")
  1055→    .action(async (opts: {
  1056→      events: string;
  1057→      sessions: string;
  1058→      state: string;
  1059→      maxLogLines: number;
  1060→      summary: boolean;
  1061→    }) => {
  1062→      await runReconstruct(opts.events, opts.sessions, opts.state, opts.maxLogLines, !opts.summary);
  1063→    });
  1064→
  1065→  // ── default: stdin hook handler ──────────────────────────────────────────
  1066→  program
  1067→    .option(
  1068→      "--events <file>",
  1069→      "Primary NDJSON event log (written before markdown, enables reconstruction)",
  1070→      defaultEventsPath,
  1071→    )
  1072→    .option(
  1073→      "-s, --sessions <file>",
  1074→      "Markdown sessions table to maintain",
  1075→      defaultSessionsPath,
  1076→    )
  1077→    .option(
  1078→      "--state <file>",
  1079→      "JSON state file for session persistence",
  1080→      "~/.claude/sessions-state.json",
  1081→    )
  1082→    .option(
  1083→      "-b, --block <pattern>",
  1084→      "Regex of tool names to block (repeatable, PreToolUse only)",
  1085→      (v: string, acc: string[]) => [...acc, v],
  1086→      [] as string[],
  1087→    )
  1088→    .option(
  1089→      "--block-reason <reason>",
  1090→      "Message sent to Claude when a tool is blocked",
  1091→      "Blocked by claude-hook-handler",
  1092→    )
  1093→    .option(
  1094→      "--no-summary",
  1095→      "Skip AI summarisation, use truncated prompt text instead",
  1096→    )
  1097→    .option(
  1098→      "--max-log-lines <n>",
  1099→      "Rotate session log files after this many lines (0 to disable)",
  1100→      (v: string) => parseInt(v, 10),
  1101→      1000,
  1102→    )
  1103→    .option("--quiet", "Suppress stderr output")
  1104→    .action(async () => {
  1105→      const opts = program.opts<{
  1106→        events: string;
  1107→        sessions: string;
  1108→        state: string;
  1109→        block: string[];
  1110→        blockReason: string;
  1111→        summary: boolean; // commander sets this from --no-summary
  1112→        maxLogLines: number;
  1113→        quiet?: boolean;
  1114→      }>();
  1115→
  1116→      const eventsPath = expandHome(opts.events);
  1117→      const sessionsPath = expandHome(opts.sessions);
  1118→      const statePath = expandHome(opts.state);
  1119→      const blockPatterns = opts.block.map((p) => new RegExp(p));
  1120→      const noSummary = !opts.summary;
  1121→
  1122→      // Read stdin
  1123→      let raw: string;
  1124→      try {
  1125→        raw = await readStdin();
  1126→      } catch (err) {
  1127→        process.stderr.write(`claude-hook-handler: failed to read stdin: ${err}\n`);
  1128→        process.exit(1);
  1129→      }
  1130→
  1131→      let input: HookInput;
  1132→      try {
  1133→        input = JSON.parse(raw) as HookInput;
  1134→      } catch {
  1135→        process.stderr.write(
  1136→          `claude-hook-handler: invalid JSON on stdin:\n${raw.slice(0, 200)}\n`,
  1137→        );
  1138→        process.exit(1);
  1139→      }
  1140→
  1141→      const blocked = shouldBlock(input, blockPatterns);
  1142→
  1143→      if (input.hook_event_name !== "Setup") {
  1144→        try {
  1145→          const state = readState(statePath);
  1146→
  1147→          // 1. Compute derived state (summary/keywords via AI if needed)
  1148→          await applyEvent(state, input, noSummary);
  1149→
  1150→          // 2. Write to NDJSON event log first — primary source of truth
  1151→          writeEventLog(eventsPath, input, blocked, state);
  1152→
  1153→          // 3. Derive markdown from state
  1154→          writeMarkdown(sessionsPath, state);
  1155→          const logPaths = appendSessionLog(sessionsPath, input, state, opts.maxLogLines);
  1156→
  1157→          // 4. Persist state (after appendSessionLog so pendingToolUses mutations are saved)
  1158→          writeState(statePath, state);
  1159→
  1160→          commitFiles(sessionsPath, [sessionsPath, ...logPaths], buildCommitMessage(input, state));
  1161→        } catch (err) {
  1162→          process.stderr.write(
  1163→            `claude-hook-handler: failed to update sessions table: ${err}\n`,
  1164→          );
  1165→          // Non-fatal — Claude Code must still get a response
  1166→        }
  1167→      }
  1168→
  1169→      // stderr summary (visible inside Claude Code)
  1170→      if (!opts.quiet) {
  1171→        process.stderr.write(formatForStderr(input, blocked) + "\n");
  1172→      }
  1173→
  1174→      // JSON response to stdout
  1175→      process.stdout.write(
  1176→        JSON.stringify(buildResponse(blocked, opts.blockReason)) + "\n",
  1177→      );
  1178→    });
  1179→
  1180→  await program.parseAsync();
  1181→}
  1182→
  1183→main().catch((err: Error) => {
  1184→  process.stderr.write(`claude-hook-handler: fatal: ${err.message}\n`);
  1185→  process.exit(1);
  1186→});
